"use client";
import { motion } from "framer-motion";

export default function Template({ children }: { children: React.ReactNode }) {
  return (
    <motion.div
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, y: -8 }}
      transition={{
        duration: 0.167,
        ease: [0.25, 0.1, 0.25, 1.0],
      }}
      suppressHydrationWarning
    >
      {children}
    </motion.div>
  );
}
